  ```
  func UserConfigDir() (string, error) {
      dir := Getenv("XDG_CONFIG_HOME")
      if dir == "" {
          dir = Getenv("HOME")
          if dir == "" {
              return "", errors.New("neither $XDG_CONFIG_HOME nor $HOME are defined")
          }
          dir += "/.config"
      } else if dir[0] != '/' {
          return "", errors.New("path in $XDG_CONFIG_HOME is relative")
      }
      return dir, nil
